fn main() {
    # We can specify the type to get a specific integer type
    let a: u8 = 2 + 1;
    print(f"2 + 1 = {a}");

    # If we don't specify the type we get i32
    let b = -10 + 3;
    print(f"-10 + 3 = {b}");

    let c = 2 * 3;
    print(f"2 * 3 = {c}");

    let d = 20 / 5;
    print(f"20 / 5 = {d}");

    let e = 23 % 5;
    print(f"23 % 5 = {e}");

    # Regular order of operations applies
    let f = 1 + 4 * 5;
    print(f"1 + 4 * 5 = {f}");
}

fn main() {
    # We can specify the type to get a specific integer type
    let a: f32 = 2.0 + 1.0; # -> 3.0
    print(f"2.0 + 1.0 = {a}");

    # We always have to write the period for floating point numbers
    let b: f32 = 2. + 1.; # -> 3.0
    print(f"2. + 1. = {b}");

    # If we don't specify the type we get f64
    let c = -12.3 + 4.5; # -> -7.8
    print(f"-12.3 + 4.5 = {c}");

    let d = 2.0 * 3.5; # -> 7.0
    print(f"2.0 * 3.5 = {d}");

    let e = 20.0 / 5.0; # -> 4.0
    print(f"20.0 / 5.0 = {e}");

    # Regular order of operations applies
    let f = 1.0 + 4.0 * 5.0; # -> 21.0
    print(f"1.0 + 4.0 * 5.0 = {f}");
}

