# Euclidean algorithm for greatest common divisor
fn main() {
    let a_initial = 125;
    let b_initial = 50;

    let a = a_initial;
    let b = b_initial;
    while b != 0 {
        let t = b;
        b = a % b;
        a = t;
    }

    print(f"gcd({a_initial}, {b_initial}) = {a}")
}
